@page "/apply"
@using sv_cd318f0065e6473bb5360dc68d23de87.Services
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1>Job Application</h1>

    @if (!_submitted)
    {
        <!-- Step Indicator Bar -->
        <div class="step-indicator">
            @for (int i = 0; i < _stepNames.Length; i++)
            {
                var stepIndex = i;
                var status = stepIndex < _currentStep ? "completed"
                           : stepIndex == _currentStep ? "active"
                           : "upcoming";
                <div class="step-item @status"
                     @onclick="() => GoToStep(stepIndex)"
                     role="button"
                     tabindex="0">
                    <div class="step-circle">
                        @if (status == "completed")
                        {
                            <span>&#10003;</span>
                        }
                        else
                        {
                            <span>@(stepIndex + 1)</span>
                        }
                    </div>
                    <div class="step-label">@_stepNames[stepIndex]</div>
                </div>
                @if (stepIndex < _stepNames.Length - 1)
                {
                    <div class="step-connector @(stepIndex < _currentStep ? "completed" : "")"></div>
                }
            }
        </div>

        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="alert alert-danger mt-3">@_error</div>
        }

        <!-- Step Content -->
        <div class="step-content mt-4">
            @switch (_currentStep)
            {
                case 0:
                    <PersonalInfoStep Model="_formState.Personal" />
                    break;
                case 1:
                    <WorkHistoryStep Entries="_formState.WorkEntries" />
                    break;
                case 2:
                    <ReferencesStep References="_formState.References" />
                    break;
                case 3:
                    <CoverLetterStep @bind-CoverLetter="_formState.CoverLetter" />
                    break;
                case 4:
                    <ReviewStep FormState="_formState" OnEditSection="GoToStep" />
                    break;
            }
        </div>

        <!-- Navigation Buttons -->
        <div class="nav-buttons mt-4">
            @if (_currentStep > 0)
            {
                <button class="btn btn-outline-secondary" @onclick="PreviousStep" disabled="@_isProcessing">
                    &larr; Back
                </button>
            }
            <div class="ms-auto">
                @if (_currentStep < _stepNames.Length - 1)
                {
                    <button class="btn btn-primary" @onclick="NextStep" disabled="@_isProcessing">
                        @if (_isProcessing)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Next &rarr;
                    </button>
                }
                else
                {
                    <button class="btn btn-success" @onclick="SubmitApplication" disabled="@_isProcessing">
                        @if (_isProcessing)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Submit Application
                    </button>
                }
            </div>
        </div>
    }
    else
    {
        <!-- Confirmation -->
        <div class="text-center mt-5">
            <div class="confirmation-icon">&#10003;</div>
            <h2 class="mt-3">Application Submitted!</h2>
            <p class="lead">Your application has been received.</p>
            <p>Your application ID is: <strong>#@_applicationId</strong></p>
