<h4>References</h4>
<p class="text-muted">Please provide 2–3 professional references.</p>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];
    <div class="reference-card">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="mb-0">Reference @(index + 1)</h6>
            @if (References.Count > 2)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">
                    Remove
                </button>
            }
        </div>

        <div class="row mb-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="reference.Name" placeholder="Reference name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="reference.Relationship" placeholder="e.g., Former Manager" />
            </div>
        </div>

        <div class="row mb-0">
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="reference.Email" placeholder="reference@example.com" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="reference.Phone" placeholder="(555) 123-4567" />
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary" @onclick="AddReference">
        + Add Reference
    </button>
}

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;

    private void AddReference() => References.Add(new ReferenceModel());

    private void RemoveReference(int index) => References.RemoveAt(index);
}
