@page "/apply"
@using sv_cd318f0065e6473bb5360dc68d23de87.Services
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1>Job Application</h1>

    @if (!_submitted)
    {
        <!-- Step Indicator Bar -->
        <div class="step-indicator">
            @for (int i = 0; i < _stepNames.Length; i++)
            {
                var stepIndex = i;
                var status = stepIndex < _currentStep ? "completed"
                           : stepIndex == _currentStep ? "active"
                           : "upcoming";
                <div class="step-item @status"
                     @onclick="() => GoToStep(stepIndex)"
                     role="button"
                     tabindex="0">
                    <div class="step-circle">
                        @if (status == "completed")
                        {
                            <span>&#10003;</span>
                        }
                        else
                        {
                            <span>@(stepIndex + 1)</span>
                        }
                    </div>
                    <div class="step-label">@_stepNames[stepIndex]</div>
                </div>
                @if (stepIndex < _stepNames.Length - 1)
                {
                    <div class="step-connector @(stepIndex < _currentStep ? "completed" : "")"></div>
                }
            }
        </div>

        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="alert alert-danger mt-3">@_error</div>
        }

        <!-- Step Content -->
        <div class="step-content mt-4">
            @switch (_currentStep)
            {
                case 0:
                    <PersonalInfoStep Model="_formState.Personal" />
                    break;
                case 1:
                    <WorkHistoryStep Entries="_formState.WorkEntries" />
                    break;
                case 2:
                    <ReferencesStep References="_formState.References" />
                    break;
                case 3:
                    <CoverLetterStep @bind-CoverLetter="_formState.CoverLetter" />
                    break;
                case 4:
                    <ReviewStep FormState="_formState" OnEditSection="GoToStep" />
                    break;
            }
        </div>

        <!-- Navigation Buttons -->
        <div class="nav-buttons mt-4">
            @if (_currentStep > 0)
            {
                <button class="btn btn-outline-secondary" @onclick="PreviousStep" disabled="@_isProcessing">
                    &larr; Back
                </button>
            }
            <div class="ms-auto">
                @if (_currentStep < _stepNames.Length - 1)
                {
                    <button class="btn btn-primary" @onclick="NextStep" disabled="@_isProcessing">
                        @if (_isProcessing)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Next &rarr;
                    </button>
                }
                else
                {
                    <button class="btn btn-success" @onclick="SubmitApplication" disabled="@_isProcessing">
                        @if (_isProcessing)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Submit Application
                    </button>
                }
            </div>
        </div>
    }
    else
    {
        <!-- Confirmation -->
        <div class="text-center mt-5">
            <div class="confirmation-icon">&#10003;</div>
            <h2 class="mt-3">Application Submitted!</h2>
            <p class="lead">Your application has been received.</p>
            <p>Your application ID is: <strong>#@_applicationId</strong></p>
            <p class="text-muted">Please save this ID for your records.</p>
        </div>
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private readonly string[] _stepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep;
    private readonly ApplicationFormState _formState = new();
    private string? _error;
    private bool _isProcessing;
    private bool _submitted;
    private int _applicationId;

    private void GoToStep(int step)
    {
        if (step < _currentStep)
        {
            _error = null;
            _currentStep = step;
        }
    }

    private async Task NextStep()
    {
        _error = null;

        if (!ValidateCurrentStep())
            return;

        if (_currentStep == 0)
        {
            _isProcessing = true;
            try
            {
                var emailValid = await ApplicationService.ValidateEmailAsync(_formState.Personal.Email);
                if (!emailValid)
                {
                    _error = "The email address could not be validated. Please check and try again.";
                    return;
                }
            }
            finally
            {
                _isProcessing = false;
            }
        }

        _currentStep++;
    }

    private void PreviousStep()
    {
        if (_currentStep > 0)
        {
            _error = null;
            _currentStep--;
        }
    }

    private bool ValidateCurrentStep()
    {
        switch (_currentStep)
        {
            case 0:
                if (string.IsNullOrWhiteSpace(_formState.Personal.FullName))
                { _error = "Full name is required."; return false; }
                if (string.IsNullOrWhiteSpace(_formState.Personal.Email))
                { _error = "Email is required."; return false; }
                if (string.IsNullOrWhiteSpace(_formState.Personal.Phone))
                { _error = "Phone number is required."; return false; }
                if (string.IsNullOrWhiteSpace(_formState.Personal.Address))
                { _error = "Address is required."; return false; }
                return true;

            case 1:
                foreach (var entry in _formState.WorkEntries)
                {
                    if (string.IsNullOrWhiteSpace(entry.Company))
                    { _error = "Company name is required for all work entries."; return false; }
                    if (string.IsNullOrWhiteSpace(entry.Title))
                    { _error = "Job title is required for all work entries."; return false; }
                    if (string.IsNullOrWhiteSpace(entry.Description))
                    { _error = "Description is required for all work entries."; return false; }
                }
                return true;

            case 2:
                foreach (var r in _formState.References)
                {
                    if (string.IsNullOrWhiteSpace(r.Name))
                    { _error = "Name is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(r.Relationship))
                    { _error = "Relationship is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(r.Email))
                    { _error = "Email is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(r.Phone))
                    { _error = "Phone is required for all references."; return false; }
                }
                return true;

            case 3:
                if (string.IsNullOrWhiteSpace(_formState.CoverLetter))
                { _error = "Cover letter is required."; return false; }
                return true;

            default:
                return true;
        }
    }

    private async Task SubmitApplication()
    {
        _error = null;
        _isProcessing = true;
        try
        {
            var application = _formState.ToRecord();
            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _error = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isProcessing = false;
        }
    }
}

